                .where('G', Predicates.blocks(GTCABlocks.STABILIZED_TRANSMUTATION_CORE.get()))
                .where('H', Predicates.blocks(GTNNCasingBlocks.ADVANCED_FILTER_CASING.get()))
                .where('I', Predicates.blocks(GTCABlocks.ULTRA_INDUCTIVE_CASING.get()))
                .where('J', Predicates.blocks(GTCABlocks.ULTRA_HIGH_STRENGTH_CONCRETE_FLOOR.get()))
                .where('K', Predicates.blocks(GTBlocks.CASING_TUNGSTENSTEEL_PIPE.get()))
                .where('L', Predicates.blocks(GTNNCasingBlocks.CASING_POLYBENZIMIDAZOLE_PIPE.get()))
                .where('M', Predicates.blocks(GTNNBlocks.HIGH_SPEED_PIPE_BLOCK.get()))
                .where(' ', Predicates.any())
                .build()
        }
        .workableCasingModel(GTCEu.id("block/casings/cleanroom/plascrete"), GTCA.id("block/multiblock/pcb_factory"))
        .register()

}